func Test_OcrError400(t *testing.T) {
	// 400 Bad Request error when OCR input has an invalid image format
	var request pkg.OcrRequest
	if err := json.Unmarshal([]byte(`{"document":{"type":"document_url","url":"invalid://url"},"model":"mistral/mistral-ocr-latest"}`), &request); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	mockURL := os.Getenv("MOCK_SERVER_URL") + "/fixtures/ocr_error_400"
	client, clientErr := pkg.CreateClient("test-key", &mockURL, nil, nil, nil)
	if clientErr != nil {
		t.Fatalf("create client failed: %v", clientErr)
	}
	_, err := client.Ocr(request)
	if err == nil {
		t.Errorf("expected an error, but call succeeded")
	}
}

